import heapq


class _Node:
    __slots__ = ("val", "next")
    def __init__(self, val):
        self.val = val
        self.next = None


def _build(values):
    head = None
    tail = None
    for v in values:
        node = _Node(v)
        if head is None:
            head = tail = node
        else:
            tail.next = node
            tail = node
    return head


def merge_k_lists(lists):
    heap = []
    counter = 0
    for values in lists:
        head = _build(values)
        if head is not None:
            heapq.heappush(heap, (head.val, counter, head))
            counter += 1

    out = []
    while heap:
        val, _, node = heapq.heappop(heap)
        out.append(val)
        if node.next is not None:
            heapq.heappush(heap, (node.next.val, counter, node.next))
            counter += 1
    return out
